BEGIN TRAN
IF EXISTS (SELECT 1 FROM <Table> WHERE <PrimaryKeyColumn> = <PrimaryKeyValue>)
    UPDATE <Table> SET <Column0>=<Value0> WHERE <PrimaryKeyColumn> = <PrimaryKeyValue>;
ELSE
    INSERT INTO <Table> (<PrimaryKeyColumn>, <Column0>) VALUES (<PrimaryKeyValue>, <Value0>);
COMMIT TRAN;

BEGIN TRAN
IF EXISTS (SELECT 1 FROM <Table> WHERE <PrimaryKeyColumn> = <PrimaryKeyValue>)
    UPDATE <Table> SET <Column0>=<Value0>, <Column1>=<Value1> WHERE <PrimaryKeyColumn> = <PrimaryKeyValue>;
ELSE
    INSERT INTO <Table> (<PrimaryKeyColumn>, <Column0>, <Column1>) VALUES (<PrimaryKeyValue>, <Value0>, <Value1>);
COMMIT TRAN;

BEGIN TRAN
IF EXISTS (SELECT 1 FROM <Table> WHERE <PrimaryKeyColumn> = <PrimaryKeyValue>)
    UPDATE <Table> SET <Column0>=<Value0>, <Column1>=<Value1>, <Column2>=<Value2> WHERE <PrimaryKeyColumn> = <PrimaryKeyValue>;
ELSE
    INSERT INTO <Table> (<PrimaryKeyColumn>, <Column0>, <Column1>, <Column2>) VALUES (<PrimaryKeyValue>, <Value0>, <Value1>, <Value2>);
COMMIT TRAN;
